class Solution:
    def largestInteger(self, nums, k):
        n = len(nums)
        windows = [set(nums[w:w + k]) for w in range(n - k + 1)]
        best = -1
        for x in set(nums):
            cnt = sum(1 for s in windows if x in s)
            if cnt == 1:
                best = max(best, x)
        return best

