class Solution:
    def largestInteger(self, nums, k):
        n = len(nums)
        if k == 1:
            from collections import Counter
            c = Counter(nums)
            cands = [v for v, cnt in c.items() if cnt == 1]
            return max(cands) if cands else -1
        if k == n:
            return max(nums)
        first, last = nums[0], nums[-1]
        cnt_first = nums.count(first)
        cnt_last = nums.count(last)
        cands = []
        if cnt_first == 1:
            cands.append(first)
        if cnt_last == 1:
            cands.append(last)
        return max(cands) if cands else -1

