var largestInteger = function(nums, k) {
    const n = nums.length;
    if (k === 1) {
        const counts = new Map();
        for (const v of nums) counts.set(v, (counts.get(v) || 0) + 1);
        let best = -1;
        for (const [v, c] of counts) {
            if (c === 1) best = Math.max(best, v);
        }
        return best;
    }
    if (k === n) {
        return Math.max(...nums);
    }
    const first = nums[0], last = nums[n - 1];
    const cntFirst = nums.filter(v => v === first).length;
    const cntLast = nums.filter(v => v === last).length;
    const cands = [];
    if (cntFirst === 1) cands.push(first);
    if (cntLast === 1) cands.push(last);
    return cands.length ? Math.max(...cands) : -1;
};
